export function quizFeedbackForLesson(
  slug: string,
  scorePercent: number,
  moduleSlug?: string
): string {
  if (scorePercent < 60) {
    return 'Herlees de les en probeer de fouten opnieuw.';
  }
  if (moduleSlug) {
    const scoped = LESSON_FEEDBACK[`${moduleSlug}:${slug}`];
    if (scoped) return scoped;
  }
  return LESSON_FEEDBACK[slug] ?? 'Goed gedaan! Je kennis groeit met elke les.';
}

export function quizResultLabel(correctCount: number, totalCount: number): string {
  if (totalCount <= 0) return '';
  if (correctCount === totalCount) return 'Uitstekend';
  if (correctCount / totalCount >= 0.6) return 'Goed bezig';
  return 'Nog oefenen';
}

export type ConfidenceLevel = 'low' | 'medium' | 'high';

export function confidenceFromScore(scorePercent: number): ConfidenceLevel {
  if (scorePercent >= 80) return 'high';
  if (scorePercent >= 60) return 'medium';
  return 'low';
}

export const CONFIDENCE_LABEL: Record<ConfidenceLevel, string> = {
  low: 'Nog oefenen',
  medium: 'Goed bezig',
  high: 'Beheerst',
};
